        my $commit_file = "$MINIGIT_DIR/commits/$current";
        last unless -f $commit_file;
        my $content = read_file($commit_file);
        my ($parent, $timestamp, $message);
        for my $line (split /\n/, $content) {
            if ($line =~ /^parent: (.*)/) { $parent = $1; }
            elsif ($line =~ /^timestamp: (.*)/) { $timestamp = $1; }
            elsif ($line =~ /^message: (.*)/) { $message = $1; }
        }
        print "\n" unless $first;
        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";
        $first = 0;
        $current = (defined $parent && $parent ne 'NONE') ? $parent : '';
    }
}

my $cmd = shift @ARGV;
unless (defined $cmd) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($cmd eq 'commit') {
    shift @ARGV; # -m
    cmd_commit(shift @ARGV);
} elsif ($cmd eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $cmd\n";
    exit 1;
}
